    // Death fields
    // -------------------------------------------------------------------------
    private float hitStopTimer;
    private float deathKnockbackDir; // +1 or -1 based on Pablo's position
    private float spinDir;           // +1 CCW, -1 CW

    // -------------------------------------------------------------------------
    // Player reference — needed only for death knockback direction
    // -------------------------------------------------------------------------
    private Pablo pablo;

    // -------------------------------------------------------------------------
    // Animations
    // -------------------------------------------------------------------------
